def gen(rng, size):
    n = 300
    ops = ['Bitset']
    args = [[n]]
    to_string_budget = 5
    for i in range(max(1, size)):
        choices = ['fix', 'unfix', 'flip', 'all', 'one', 'count']
        if to_string_budget > 0 and i % 80 == 0:
            choices.append('toString')
        m = rng.choice(choices)
        if m == 'toString':
            to_string_budget -= 1
            ops.append('toString'); args.append([])
        elif m in ('fix', 'unfix'):
            ops.append(m); args.append([rng.randint(0, n - 1)])
        else:
            ops.append(m); args.append([])
    return [ops, args]

