class Bitset:
    def __init__(self, size):
        self.n = size
        self.arr = [0] * size
        self.raw_ones = 0
        self.flipped = False

    def fix(self, idx):
        desired = 0 if self.flipped else 1
        if self.arr[idx] != desired:
            self.arr[idx] = desired
            self.raw_ones += 1 if desired == 1 else -1

    def unfix(self, idx):
        desired = 1 if self.flipped else 0
        if self.arr[idx] != desired:
            self.arr[idx] = desired
            self.raw_ones += 1 if desired == 1 else -1

    def flip(self):
        self.flipped = not self.flipped

    def _actual_ones(self):
        return self.n - self.raw_ones if self.flipped else self.raw_ones

    def all(self):
        return self._actual_ones() == self.n

    def one(self):
        return self._actual_ones() > 0

    def count(self):
        return self._actual_ones()

    def toString(self):
        bit = 1 if self.flipped else 0
        return ''.join(str(v ^ bit) for v in self.arr)

