class Bitset {
    constructor(size) {
        this.n = size;
        this.arr = new Array(size).fill(0);
        this.rawOnes = 0;
        this.flipped = false;
    }

    fix(idx) {
        const desired = this.flipped ? 0 : 1;
        if (this.arr[idx] !== desired) {
            this.arr[idx] = desired;
            this.rawOnes += desired === 1 ? 1 : -1;
        }
    }

    unfix(idx) {
        const desired = this.flipped ? 1 : 0;
        if (this.arr[idx] !== desired) {
            this.arr[idx] = desired;
            this.rawOnes += desired === 1 ? 1 : -1;
        }
    }

    flip() {
        this.flipped = !this.flipped;
    }

    _actualOnes() {
        return this.flipped ? this.n - this.rawOnes : this.rawOnes;
    }

    all() {
        return this._actualOnes() === this.n;
    }

    one() {
        return this._actualOnes() > 0;
    }

    count() {
        return this._actualOnes();
    }

    toString() {
        const bit = this.flipped ? 1 : 0;
        let out = '';
        for (let i = 0; i < this.n; i++) out += (this.arr[i] ^ bit).toString();
        return out;
    }
}
